// Validar y limpiar filas del tarifario
const rows = $input.all();
const valid = [];
const errors = [];

for (const item of rows) {
  const row = item.json;
  const rowNum = rows.indexOf(item) + 2; // +2 porque fila 1 es header

  // Validaciones
  if (!row.contratista_id) { errors.push(`Fila ${rowNum}: contratista_id vacío`); continue; }
  if (!row.tipo_servicio) { errors.push(`Fila ${rowNum}: tipo_servicio vacío`); continue; }
  if (!row.tarifa || isNaN(Number(row.tarifa)) || Number(row.tarifa) <= 0) {
    errors.push(`Fila ${rowNum}: tarifa inválida (${row.tarifa})`); continue;
  }
  if (!row.effective_from || isNaN(Date.parse(row.effective_from))) {
    errors.push(`Fila ${rowNum}: effective_from inválido (${row.effective_from})`); continue;
  }

  valid.push({
    json: {
      contratista_id: String(row.contratista_id).trim(),
      contratista_nombre: String(row.contratista_nombre || '').trim(),
      tipo_servicio: String(row.tipo_servicio).trim().toUpperCase(),
      zona: row.zona ? String(row.zona).trim() : null,
      or_codigo: row.or_codigo ? String(row.or_codigo).trim() : null,
      unidad: String(row.unidad || 'und').trim(),
      tarifa: Number(String(row.tarifa).replace(/[^0-9.]/g, '')),
      moneda: String(row.moneda || 'COP').trim().toUpperCase(),
      tolerancia_pct: row.tolerancia_pct ? Number(row.tolerancia_pct) : 3.0,
      es_tarifa_variable: String(row.es_tarifa_variable || 'NO').toUpperCase() === 'SI',
      cap_mensual: row.cap_mensual ? Number(String(row.cap_mensual).replace(/[^0-9.]/g, '')) : null,
      notas: row.notas || null,
      effective_from: row.effective_from,
      effective_to: row.effective_to || null,
      version: 1,
      creado_por: 'wf_01_sync'
    }
  });
}

// Guardar errores en el primer item para logging posterior
if (errors.length > 0) {
  $execution.customData.set('tarifario_errors', JSON.stringify(errors));
}

return valid;

// Validar y limpiar filas del budget
const rows = $input.all();
const valid = [];
const errors = [];

for (const item of rows) {
  const row = item.json;
  const rowNum = rows.indexOf(item) + 2;

  if (!row.anio || isNaN(Number(row.anio))) { errors.push(`Fila ${rowNum}: anio inválido`); continue; }
  if (!row.mes || Number(row.mes) < 1 || Number(row.mes) > 12) { errors.push(`Fila ${rowNum}: mes inválido`); continue; }
  if (!row.categoria_contable) { errors.push(`Fila ${rowNum}: categoria_contable vacío`); continue; }
  if (row.monto_budget === undefined || isNaN(Number(row.monto_budget))) {
    errors.push(`Fila ${rowNum}: monto_budget inválido`); continue;
  }

  valid.push({
    json: {
      anio: Number(row.anio),
      mes: Number(row.mes),
      zona: row.zona ? String(row.zona).trim() : null,
      contratista_id: row.contratista_id ? String(row.contratista_id).trim() : null,
      categoria_contable: String(row.categoria_contable).trim(),
      tipo_servicio: row.tipo_servicio ? String(row.tipo_servicio).trim().toUpperCase() : null,
      monto_budget: Number(String(row.monto_budget).replace(/[^0-9.]/g, '')),
      moneda: String(row.moneda || 'COP').toUpperCase(),
      notas: row.notas || null,
      effective_from: row.effective_from || new Date().toISOString().split('T')[0],
      effective_to: row.effective_to || null,
      version: 1,
      creado_por: 'wf_01_sync'
    }
  });
}

if (errors.length > 0) {
  $execution.customData.set('budget_errors', JSON.stringify(errors));
}

return valid;

// Consolidar resultados y determinar si hay alertas de cambio brusco de tarifa
const tarifarioErrors = $execution.customData.get('tarifario_errors');
const budgetErrors = $execution.customData.get('budget_errors');

const errorsT = tarifarioErrors ? JSON.parse(tarifarioErrors) : [];
const errorsB = budgetErrors ? JSON.parse(budgetErrors) : [];
const allErrors = [...errorsT, ...errorsB];

return [{
  json: {
    sync_ok: allErrors.length === 0,
    total_errors: allErrors.length,
    errors: allErrors,
    timestamp: new Date().toISOString()
  }
}];

